from utime import sleep
import random
import _thread


def shuffle(l):
    for i in range(len(l) - 1, 0, -1):
        j = random.randrange(i + 1)
        l[i], l[j] = l[j], l[i]

led = Pin("LED", Pin.OUT)

led.on()

print("setting pins...")

pwma = PWM(Pin(19))
ain2 = Pin(20, Pin.OUT)
ain1 = Pin(21, Pin.OUT)
vcc = "VCC"
stby = Pin(3, Pin.OUT)
gnd = "GND"
bin1 = Pin(2, Pin.OUT)
bin2 = Pin(1, Pin.OUT)
pwmb = PWM(Pin(0))

#driver 2
pwmc = PWM(Pin(12))
cin2 = Pin(17, Pin.OUT)
cin1 = Pin(16, Pin.OUT)
vcc = "VCC"
stby2 = Pin(9, Pin.OUT)
gnd = "GND"
din1 = Pin(10, Pin.OUT)
din2 = Pin(11, Pin.OUT)
pwmd = PWM(Pin(18))

print("setting PWM...")
pwma.freq(10000)
pwma.duty_u16(0)
pwmb.freq(10000)
pwmb.duty_u16(0)
pwmc.freq(10000)
pwmc.duty_u16(0)
pwmd.freq(10000)
pwmd.duty_u16(0)

def brake():
    ain1.on()
    ain2.on()
    bin1.on()
    bin2.on()
    cin1.on()
    cin2.on()
    din1.on()
    din2.on()


def forward():
    ain1.on()
    ain2.off()
    bin1.on()
    bin2.off()
    cin1.on()
    cin2.off()
    din1.on()
    din2.off()
    
def reverse():
    ain1.off()
    ain2.on()
    bin1.off()
    bin2.on()
    cin1.off()
    cin2.on()
    din1.off()
    din2.on()

def free():
    ain1.off()
    ain2.off()
    bin1.off()
    bin2.off()
    cin1.off()
    cin2.off()
    din1.off()
    din2.off()


free()

led.off()

print("start")

led.on()

stby.on()
stby2.on()

forward()

pwma.duty_u16(2000)
pwmb.duty_u16(2000)
pwmc.duty_u16(2000)
pwmd.duty_u16(2000)

